import{_ as a,o as t,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"🥇 黃金追蹤日誌 — 20260501","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_20260501.md","filePath":"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_20260501.md"}'),s={name:"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_20260501.md"};function l(i,e,n,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🥇-黃金追蹤日誌-—-20260501" tabindex="-1">🥇 黃金追蹤日誌 — 20260501 <a class="header-anchor" href="#🥇-黃金追蹤日誌-—-20260501" aria-label="Permalink to &quot;🥇 黃金追蹤日誌 — 20260501&quot;">​</a></h1><blockquote><p>掃描時間：2026-05-01 Asia/Taipei 21:25 搜尋工具：web_search (Google Search grounding)</p></blockquote><hr><h2 id="📋-10-項追蹤指標" tabindex="-1">📋 10 項追蹤指標 <a class="header-anchor" href="#📋-10-項追蹤指標" aria-label="Permalink to &quot;📋 10 項追蹤指標&quot;">​</a></h2><h3 id="_1-現貨價" tabindex="-1">1. 現貨價 <a class="header-anchor" href="#_1-現貨價" aria-label="Permalink to &quot;1. 現貨價&quot;">​</a></h3><p><strong>$4,571.84/盎司</strong>（5/1，-$11.42，-1.10%）。年增 <strong>41.13%</strong>。歷史高 $5,589（1/28）。 <em>來源：TradingEconomics — <a href="https://tradingeconomics.com/commodity/gold" target="_blank" rel="noreferrer">https://tradingeconomics.com/commodity/gold</a></em></p><h3 id="_2-期貨價" tabindex="-1">2. 期貨價 <a class="header-anchor" href="#_2-期貨價" aria-label="Permalink to &quot;2. 期貨價&quot;">​</a></h3><p>COMEX 5 月合約（GCK26）：4/30 收 <strong>$4,614.70</strong>（月跌 0.71%，兩月累跌 11.77%）。第一通知日 4/30，到期日 5/27。52 週高 $5,645.6 / 低 $3,329.4。 <em>來源：CME Group — <a href="https://www.cmegroup.com/markets/metals/precious/gold.quotes.html" target="_blank" rel="noreferrer">https://www.cmegroup.com/markets/metals/precious/gold.quotes.html</a>, Morningstar</em></p><h3 id="_3-技術線-ma20-ma60-rsi" tabindex="-1">3. 技術線（MA20/MA60/RSI） <a class="header-anchor" href="#_3-技術線-ma20-ma60-rsi" aria-label="Permalink to &quot;3. 技術線（MA20/MA60/RSI）&quot;">​</a></h3><ul><li><strong>MA50</strong>：$4,842（關鍵阻力）</li><li>支撐區：$4,400-$4,500</li><li>跌破 $4,400 則測試 $4,275 甚至 $4,000</li><li>RSI 接近中性區，短期動能偏弱</li><li>分析師建議在 $4,400-$4,600 區間逢低買入 <em>來源：FX Empire — <a href="https://www.fxempire.com/forecasts/article/gold-and-silver-technical-analysis-oil-shock-keeps-metals-under-pressure-1595156" target="_blank" rel="noreferrer">https://www.fxempire.com/forecasts/article/gold-and-silver-technical-analysis-oil-shock-keeps-metals-under-pressure-1595156</a>, LiteFinance</em></li></ul><h3 id="_4-美元指數" tabindex="-1">4. 美元指數 <a class="header-anchor" href="#_4-美元指數" aria-label="Permalink to &quot;4. 美元指數&quot;">​</a></h3><p>DXY <strong>98.11</strong>（5/1，+0.05%），月跌 <strong>1.88%</strong>。美元走弱支撐金價。 <em>來源：Investing.com — <a href="https://www.investing.com/indices/usdollar" target="_blank" rel="noreferrer">https://www.investing.com/indices/usdollar</a></em></p><h3 id="_5-美-10-年期殖利率" tabindex="-1">5. 美 10 年期殖利率 <a class="header-anchor" href="#_5-美-10-年期殖利率" aria-label="Permalink to &quot;5. 美 10 年期殖利率&quot;">​</a></h3><p>10 年期 TIPS 實質利率 <strong>1.96%</strong>（高檔，壓制金價）。名目殖利率（10 年）約 <strong>4.2-4.4%</strong>。高殖利率為金價主要逆風。 <em>來源：StreetStats — <a href="https://streetstats.finance/rates/tips" target="_blank" rel="noreferrer">https://streetstats.finance/rates/tips</a></em></p><h3 id="_6-聯邦基金利率預期" tabindex="-1">6. 聯邦基金利率預期 <a class="header-anchor" href="#_6-聯邦基金利率預期" aria-label="Permalink to &quot;6. 聯邦基金利率預期&quot;">​</a></h3><p>聯準會 4/29 維持 <strong>3.5%-3.75%</strong>。市場提前放棄 2026 年降息押注，重新定價 2027 年升息可能性。BoE 維持 3.75% 且有升息壓力，ECB 維持 2.00%。 <em>來源：ECB — <a href="https://www.ecb.europa.eu" target="_blank" rel="noreferrer">https://www.ecb.europa.eu</a>, BoE — <a href="https://www.bankofengland.co.uk" target="_blank" rel="noreferrer">https://www.bankofengland.co.uk</a></em></p><h3 id="_7-etf-持倉-gld-iau" tabindex="-1">7. ETF 持倉（GLD/IAU） <a class="header-anchor" href="#_7-etf-持倉-gld-iau" aria-label="Permalink to &quot;7. ETF 持倉（GLD/IAU）&quot;">​</a></h3><ul><li><strong>GLD</strong>（SPDR Gold Shares）：約 <strong>$423.66-425.00/股</strong>，市值 $1,520-1,540 億</li><li>4/29 一度跌至 $416.94（地緣緊張+通膨擔憂）</li><li>WGC 預測降息預期後退可能影響 ETF 流入 <em>來源：Google Finance, Investing.com — <a href="https://www.investing.com/etfs/spdr-gold-trust" target="_blank" rel="noreferrer">https://www.investing.com/etfs/spdr-gold-trust</a>, BlackRock</em></li></ul><h3 id="_8-各國央行購金" tabindex="-1">8. 各國央行購金 <a class="header-anchor" href="#_8-各國央行購金" aria-label="Permalink to &quot;8. 各國央行購金&quot;">​</a></h3><p>WGC Q1 2026 報告：央行淨購金 <strong>244 噸</strong>（高於五年平均）。主要買家：波蘭（20.23t）、烏茲別克（16.48t）、哈薩克（6.51t）、中國（2.18t）。賣家：俄羅斯（-15.55t）、土耳其（-8.08t）。去美元化趨勢持續。 <em>來源：WGC — <a href="https://www.gold.org/goldhub/research/gold-demand-trends/gold-demand-trends-q1-2026/central-banks" target="_blank" rel="noreferrer">https://www.gold.org/goldhub/research/gold-demand-trends/gold-demand-trends-q1-2026/central-banks</a>, VisualCapitalist — <a href="https://elements.visualcapitalist.com/central-banks-buying-and-selling-gold-in-2026/" target="_blank" rel="noreferrer">https://elements.visualcapitalist.com/central-banks-buying-and-selling-gold-in-2026/</a></em></p><h3 id="_9-vix-恐慌指數" tabindex="-1">9. VIX 恐慌指數 <a class="header-anchor" href="#_9-vix-恐慌指數" aria-label="Permalink to &quot;9. VIX 恐慌指數&quot;">​</a></h3><p>VIX 約 <strong>17.48</strong>。VIXY 約 $27.75。VIX 未顯著飆升，顯示市場尚未陷入極度恐慌。但歷史數據顯示 VIX 與金價在極端事件中正相關。目前 VIX 偏低 + 地緣風險高檔 = 金價可能未充分反映風險。 <em>來源：Cboe — <a href="https://www.cboe.com" target="_blank" rel="noreferrer">https://www.cboe.com</a>, Fidelity — <a href="https://digital.fidelity.com" target="_blank" rel="noreferrer">https://digital.fidelity.com</a></em></p><h3 id="_10-地緣政治風險" tabindex="-1">10. 地緣政治風險 <a class="header-anchor" href="#_10-地緣政治風險" aria-label="Permalink to &quot;10. 地緣政治風險&quot;">​</a></h3><ul><li>🔴 <strong>荷莫茲第 63 天封閉</strong>：伊朗領袖強硬表態，短期無重開跡象</li><li>🔴 <strong>美伊衝突持續</strong>：油價 $106-$111 維持高檔</li><li>🟡 <strong>印度 5/4 選舉結果</strong>：預期波動</li><li>🟡 <strong>全球債務 $350 兆警示</strong><em>來源：Economictimes — <a href="https://economictimes.indiatimes.com/markets/commodities/news/oil-price-today-may-1-crude-oil-holds-above-110/barrel-what-lies-ahead/articleshow/130665530.cms" target="_blank" rel="noreferrer">https://economictimes.indiatimes.com/markets/commodities/news/oil-price-today-may-1-crude-oil-holds-above-110/barrel-what-lies-ahead/articleshow/130665530.cms</a></em></li></ul><hr><h2 id="🗞️-5-條黃金相關新聞" tabindex="-1">🗞️ 5 條黃金相關新聞 <a class="header-anchor" href="#🗞️-5-條黃金相關新聞" aria-label="Permalink to &quot;🗞️ 5 條黃金相關新聞&quot;">​</a></h2><h3 id="新聞-1-金價技術修正-4-600-為關鍵支撐" tabindex="-1">新聞 1：金價技術修正，$4,600 為關鍵支撐 <a class="header-anchor" href="#新聞-1-金價技術修正-4-600-為關鍵支撐" aria-label="Permalink to &quot;新聞 1：金價技術修正，$4,600 為關鍵支撐&quot;">​</a></h3><p>5/1 金價跌至 $4,571.84（-1.10%），本週週線下跌。$4,600 為近期操作關鍵位，$4,950 為阻力。年增達 41% 但短期面臨技術修正壓力。 <em>來源：TradingEconomics — <a href="https://tradingeconomics.com/commodity/gold" target="_blank" rel="noreferrer">https://tradingeconomics.com/commodity/gold</a>, DailyForex</em></p><h3 id="新聞-2-ubs-上修金價目標至-6-200-deutsche-bank-看-8-000" tabindex="-1">新聞 2：UBS 上修金價目標至 $6,200，Deutsche Bank 看 $8,000 <a class="header-anchor" href="#新聞-2-ubs-上修金價目標至-6-200-deutsche-bank-看-8-000" aria-label="Permalink to &quot;新聞 2：UBS 上修金價目標至 $6,200，Deutsche Bank 看 $8,000&quot;">​</a></h3><p>UBS 預測 2026 年 9 月前金價達 <strong>$6,200/盎司</strong>（潛力 $7,200）。J.P. Morgan Q4 均價 $5,055。Goldman Sachs $5,400。Deutsche Bank 5 年內可能觸及 <strong>$8,000</strong>（去美元化驅動）。 <em>來源：Investing.com — <a href="https://www.investing.com/news/commodities-news/these-drivers-could-push-gold-prices-toward-5900oz-by-late-2026-ubs-4649617" target="_blank" rel="noreferrer">https://www.investing.com/news/commodities-news/these-drivers-could-push-gold-prices-toward-5900oz-by-late-2026-ubs-4649617</a>, JPMorgan — <a href="https://www.jpmorgan.com/insights/global-research/commodities/gold-prices" target="_blank" rel="noreferrer">https://www.jpmorgan.com/insights/global-research/commodities/gold-prices</a></em></p><h3 id="新聞-3-央行-q1-購金-244-噸-波蘭領跑" tabindex="-1">新聞 3：央行 Q1 購金 244 噸，波蘭領跑 <a class="header-anchor" href="#新聞-3-央行-q1-購金-244-噸-波蘭領跑" aria-label="Permalink to &quot;新聞 3：央行 Q1 購金 244 噸，波蘭領跑&quot;">​</a></h3><p>WGC 公布 Q1 央行淨購金 244 噸，季增且高於五年平均。波蘭（20.23t）、烏茲別克（16.48t）領跑。俄羅斯（-15.55t）和土耳其（-8.08t）為淨賣家。 <em>來源：WGC — <a href="https://www.gold.org/goldhub/research/gold-demand-trends/gold-demand-trends-q1-2026/central-banks" target="_blank" rel="noreferrer">https://www.gold.org/goldhub/research/gold-demand-trends/gold-demand-trends-q1-2026/central-banks</a>, VisualCapitalist — <a href="https://elements.visualcapitalist.com/central-banks-buying-and-selling-gold-in-2026/" target="_blank" rel="noreferrer">https://elements.visualcapitalist.com/central-banks-buying-and-selling-gold-in-2026/</a></em></p><h3 id="新聞-4-荷莫茲封閉推升通膨預期-金價多空拉鋸" tabindex="-1">新聞 4：荷莫茲封閉推升通膨預期，金價多空拉鋸 <a class="header-anchor" href="#新聞-4-荷莫茲封閉推升通膨預期-金價多空拉鋸" aria-label="Permalink to &quot;新聞 4：荷莫茲封閉推升通膨預期，金價多空拉鋸&quot;">​</a></h3><p>荷莫茲封閉（第 63 天）推高油價至 $111，通膨預期上升。金價短期面臨高實質利率（TIPS 1.96%）和聯準會不降息的逆風，但地緣避險需求提供底部支撐。 <em>來源：Seeking Alpha — <a href="https://seekingalpha.com/article/4889444-gold-volatility-amid-geopolitical-crises-what-history-tells-us" target="_blank" rel="noreferrer">https://seekingalpha.com/article/4889444-gold-volatility-amid-geopolitical-crises-what-history-tells-us</a>, Advantage Gold</em></p><h3 id="新聞-5-分析師建議-4-400-4-600-區間逢低建立多頭" tabindex="-1">新聞 5：分析師建議 $4,400-$4,600 區間逢低建立多頭 <a class="header-anchor" href="#新聞-5-分析師建議-4-400-4-600-區間逢低建立多頭" aria-label="Permalink to &quot;新聞 5：分析師建議 $4,400-$4,600 區間逢低建立多頭&quot;">​</a></h3><p>多家分析師認為金價在 $4,400-$4,600 區間是逢低建立多頭的機會，預測美元走弱和實質利率下降將推動金價在年底前重回 $5,000+。WGC 情境：若全球衰退則可能 +15-30%。 <em>來源：MarketPulse, LiteFinance — <a href="https://www.litefinance.org/blog/analysts-opinions/short-term-analysis-for-oil-gold-and-eurusd-for-01052026/" target="_blank" rel="noreferrer">https://www.litefinance.org/blog/analysts-opinions/short-term-analysis-for-oil-gold-and-eurusd-for-01052026/</a></em></p><hr><h2 id="📚-資料來源-全" tabindex="-1">📚 資料來源（全） <a class="header-anchor" href="#📚-資料來源-全" aria-label="Permalink to &quot;📚 資料來源（全）&quot;">​</a></h2><ol><li>TradingEconomics Gold: <a href="https://tradingeconomics.com/commodity/gold" target="_blank" rel="noreferrer">https://tradingeconomics.com/commodity/gold</a></li><li>CME Group Gold: <a href="https://www.cmegroup.com/markets/metals/precious/gold.quotes.html" target="_blank" rel="noreferrer">https://www.cmegroup.com/markets/metals/precious/gold.quotes.html</a></li><li>WGC Central Banks Q1 2026: <a href="https://www.gold.org/goldhub/research/gold-demand-trends/gold-demand-trends-q1-2026/central-banks" target="_blank" rel="noreferrer">https://www.gold.org/goldhub/research/gold-demand-trends/gold-demand-trends-q1-2026/central-banks</a></li><li>VisualCapitalist CB Gold 2026: <a href="https://elements.visualcapitalist.com/central-banks-buying-and-selling-gold-in-2026/" target="_blank" rel="noreferrer">https://elements.visualcapitalist.com/central-banks-buying-and-selling-gold-in-2026/</a></li><li>Investing.com UBS: <a href="https://www.investing.com/news/commodities-news/these-drivers-could-push-gold-prices-toward-5900oz-by-late-2026-ubs-4649617" target="_blank" rel="noreferrer">https://www.investing.com/news/commodities-news/these-drivers-could-push-gold-prices-toward-5900oz-by-late-2026-ubs-4649617</a></li><li>JPMorgan Gold: <a href="https://www.jpmorgan.com/insights/global-research/commodities/gold-prices" target="_blank" rel="noreferrer">https://www.jpmorgan.com/insights/global-research/commodities/gold-prices</a></li><li>StreetStats TIPS: <a href="https://streetstats.finance/rates/tips" target="_blank" rel="noreferrer">https://streetstats.finance/rates/tips</a></li><li>Cboe VIX: <a href="https://www.cboe.com" target="_blank" rel="noreferrer">https://www.cboe.com</a></li><li>FX Empire TA: <a href="https://www.fxempire.com/forecasts/article/gold-and-silver-technical-analysis-oil-shock-keeps-metals-under-pressure-1595156" target="_blank" rel="noreferrer">https://www.fxempire.com/forecasts/article/gold-and-silver-technical-analysis-oil-shock-keeps-metals-under-pressure-1595156</a></li><li>LiteFinance: <a href="https://www.litefinance.org/blog/analysts-opinions/short-term-analysis-for-oil-gold-and-eurusd-for-01052026/" target="_blank" rel="noreferrer">https://www.litefinance.org/blog/analysts-opinions/short-term-analysis-for-oil-gold-and-eurusd-for-01052026/</a></li><li>Investing.com DXY: <a href="https://www.investing.com/indices/usdollar" target="_blank" rel="noreferrer">https://www.investing.com/indices/usdollar</a></li><li>Seeking Alpha: <a href="https://seekingalpha.com/article/4889444-gold-volatility-amid-geopolitical-crises-what-history-tells-us" target="_blank" rel="noreferrer">https://seekingalpha.com/article/4889444-gold-volatility-amid-geopolitical-crises-what-history-tells-us</a></li></ol><hr><p><em>報告產出：Dr.32 知識管家 | 抓取時間：2026-05-01 Asia/Taipei 21:25</em></p>',41)])])}const p=a(s,[["render",l]]);export{g as __pageData,p as default};
